var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"하담이 네가 밤마다 꿈을 꾼다고 들었다.","JPN":"カタン、毎晩夢を見ると聞いた。","ENG":"Ha Dam, I heard you've been dreaming every night.","TWN":"我聽說夏垣你每天晚上都會做夢。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그것은 어떤 꿈이냐?","JPN":"どんな夢なんだ？","ENG":"What kind of dreams are they?","TWN":"那是什麼樣的夢？"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"살아본 적 없는 타인의 삶을 마치 제 것처럼 들여다 보며, 생과 사를 반복하는 꿈이요.","JPN":"生きたことのない他人の生が、まるで己の生のごとく映し出され……生と死を繰り返す夢だ。","ENG":"Dreams where I see the life of someone I've never been as if it were my own. I live and die, again and again.","TWN":"像親身經歷一樣，看著一個從未活過的陌生人的生活，並不斷地重複生與死。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그 꿈에선 언제나 아름다운 여인이 나타나곤 하지.","JPN":"その夢では必ず美しい女性が現れる。","ENG":"And in those dreams, there's always a beautiful woman.","TWN":"在那個夢裡，總會出現一位美麗的女人。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그 여인은 매번 똑같은 모습이더냐?","JPN":"その女性は、毎回同じ姿をしていたか？","ENG":"Does she always look the same?","TWN":"那位女人每次都長得一樣嗎？"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"아니. 꿈을 꿀 때마다 다른 사람이었소.","JPN":"いいや、夢のたびに違う姿をしていた。","ENG":"No. She's someone different each time.","TWN":"不。每次做夢，她都是不同的人。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"하나 닮은 것이 있다면… 여인은 날 항상 서생이라 부르더구려.","JPN":"1つ共通点があるとするなら……女性はいつも某のことを「ショウ」と呼んでいた。","ENG":"But there's one thing that stays the same… She always calls me Seosaeng.","TWN":"但有一點很像…女人總會叫我書生。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그렇다면 그건 꿈이 아닐 게다.","JPN":"ならばそれは夢ではないだろう。","ENG":"Then it's no ordinary dream.","TWN":"那樣的話，那不是夢。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"꿈이 아니라면 무엇이요?","JPN":"夢でないとするなら何なのだ？","ENG":"Then what would you call it?","TWN":"如果不是夢，那是什麼？"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"지난 삶에 대한 일종의 기시감이지.","JPN":"前世に対する、ある種の既視感だ。","ENG":"A kind of deja vu.","TWN":"是一種對過往人生的既視感。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"예스러운 물건이 이상하리만치 익숙하다거나, 첫 사격훈련에서 만점을 받는 것처럼 말이야.","JPN":"古めかしいものが妙にしっくりきたり、初めての射撃訓練なのに満点を取ったりするのと同じことだ。","ENG":"Like recognizing an ancient relic you've never seen before, or landing a perfect score your first time on the range.","TWN":"就像對某件古董感到異常熟悉，或是在第一次射擊訓練就拿到滿分一樣。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"만점을 받은 건 본인의 천부적인 재능의 덕이라 생각했소만.","JPN":"満点を取ったのは、某の天賦の才ゆえと思っていたのだが。","ENG":"I assumed that was just thanks to my natural talent.","TWN":"我以為拿到滿分是我的天賦。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"하하, 젊은 천재는 그런 한물 간 말투를 쓰지 않아.","JPN":"ははは、若き天才はそんな時代劇みたいな喋り方はしないものだ。","ENG":"Haha. Young prodigies don't talk like that.","TWN":"哈哈，年輕的天才可不會用那種過時的說話方式。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"네가 특출한 것은 그러한 삶을 수 십, 수 백 번 거듭해왔기 때문이지.","JPN":"お前の能力が優れているのは、そういう生を数十回、数百回重ねてきたからであろう。","ENG":"You stand out because you've lived that kind of life dozens, even hundreds of times over.","TWN":"你之所以與眾不同，是因為你已經重複過數十、數百次那樣的生活。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"명달 대장의 말씀은 이 몸뚱이에 아주 오래된 정신이라도 깃들어있단 뜻이오?","JPN":"アカタツ隊長は、この身にいにしえの魂が宿っているとでも言われるのか？","ENG":"So what you're saying is that this body houses a soul that's far older than it seems?","TWN":"明達隊長的意思是，這個身體裡寄宿著一個非常古老的靈魂嗎？"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"비슷하다.","JPN":"そうだな。","ENG":"Close enough.","TWN":"差不多。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그 오래된 정신은 죽음으로도 끊어내지 못하여, 삶을 거듭할 때마다 따라붙는… 질긴 저주 같은 게야.","JPN":"その古い魂は死をもっても断ち切ることができず、生を重ねるたびにつきまとう……しつこい呪いのようなものだ。","ENG":"That old soul clings to you even in death. A curse… that sticks through every life you live.","TWN":"那個古老的靈魂，是連死亡都無法切斷，每次轉世都會跟隨的…像一個頑固的詛咒。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"나는 그것을 <color=#ffd34c>땅내림</color>이라 부른다.","JPN":"俺はそれを<color=#ffd34c>チガカリ</color>と呼んでいる。","ENG":"I call it <color=#ffd34c>Earthbound</color>.","TWN":"我稱之為<color=#ffd34c>地脈之力</color>。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"요컨대…","JPN":"つまるところ……","ENG":"If I understand correctly…","TWN":"總而言之…"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"윤회란 것이 실재하여, 본인과 같은 운명을 가진 사람이 관리국과 함께 일해왔다는 말씀이구려.","JPN":"輪廻というものは実在し、某と同じ運命を持つ者が管理局と力を合わせ働いていた、ということか。","ENG":"Reincarnation is real, and others like me have worked with the Administration before.","TWN":"輪迴是真實存在的，而擁有和我一樣命運的人，一直以來都和管理局一起工作？"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Exactly.","TWN":"對。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"천재가 될 운명도 타고나는 것인지- 넌 매 생애마다 훌륭한 발명품을 만들어내었다.","JPN":"天才になる運命も生まれつきなのか、お前は毎回の人生で立派な発明品を生み出した。","ENG":"Fate seems to favor your mind. You've invented something remarkable in every life.","TWN":"或許連成為天才的命運都是注定的，你在每一次生命中都創造出優秀的發明。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그리고 늘 마지막엔 터무니없는 이유로 죽었어. 똑같은 운명의 굴레에 갇혀 장생을 이루지 못하고 단명을 되풀이하는 게지.","JPN":"そして最後は必ず理不尽な理由で死ぬ。同じ運命の輪に囚われ長寿を全うできず、短命を繰り返すのだ。","ENG":"But every time, your story ends the same. You die for some absurd reason. A genius fated to burn out early, never escaping that loop.","TWN":"但每次最後都死於荒謬的理由。被困在同樣的命運輪迴中，無法長生，不斷地重複短命。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그런 운명을 되풀이하는 연유는 어떤 죽지 않는 호랑이가 내게 <color=#ffd34c>땅내림</color>이란 저주를 내렸기 때문이라 하셨고 말이오.","JPN":"某がそのような運命を繰り返す所以は、とある不死の虎が某に<color=#ffd34c>チガカリ</color>という呪いをかけたゆえであると言われるのだな。","ENG":"And this cycle. You said it began when some immortal Tiger laid a curse called <color=#ffd34c>Earthbound</color> upon me.","TWN":"而重複那樣命運的原因，是因為一隻不死的老虎對我施下名為<color=#ffd34c>地脈之力</color>的詛咒？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"우린 그 죽지 않는 호랑이를 <color=#ffd34c>짐승</color>이라 부르지.","JPN":"俺たちはその不死の虎を<color=#ffd34c>ケモノ</color>と呼んでいる。","ENG":"We call that immortal Tiger, <color=#ffd34c>the Beast</color>.","TWN":"我們稱那隻不死的老虎為<color=#ffd34c>野獸<color=#ffd34c>。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"관리국은 꽤 오랜 시간 <color=#ffd34c>짐승</color>을 처리하기 위해 싸워왔다. 지금도 마찬가지고.","JPN":"管理局は非常に長い年月の間、<color=#ffd34c>ケモノ</color>を始末するために戦ってきた。それは今も変わらない。","ENG":"The Administration has been fighting to eliminate <color=#ffd34c>the Beasts</color> for a long time. Even to this day.","TWN":"管理局花費很長一段時間來對付<color=#ffd34c>野獸</color>。現在也一樣。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"혹, 말씀하신 짐승이란 존재가 본인의 고향을 쑥대밭으로 만든 큰 괴물을 말하는 것이요?","JPN":"もしやケモノとは、某の故郷を襲ったあの巨体な化け物のことか？","ENG":"Are we talking about the same Beast that razed my hometown?","TWN":"你說的野獸，是指毀掉我故鄉的那個怪物嗎？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};